/**
 * Get file metadata without downloading content.

HEAD requests are often used before Range GETs to ensure the server
supports partial downloads (e.g., DuckDB's httpfs).
Returns Accept-Ranges, Content-Length, and Content-Type headers.
 * @summary Get File Metadata
 */
export const FilesHeadFileParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
  path: zod.string(),
});

export const FilesHeadFileResponse = zod.unknown();

/**
 * Download file content from a fileset.

Supports HTTP Range requests for partial content retrieval (status 206).
Returns the full file content (status 200) if no Range header is provided.
For external resources (HuggingFace, NGC), content is cached locally on first access.
 * @summary Download File Content
 */
export const FilesDownloadFileParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
  path: zod.string(),
});

/**
 * Upload file content to a fileset.
 * @summary Upload Fileset Content
 */
export const FilesUploadFileParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
  path: zod.string(),
});

export const FilesUploadFileResponse = zod.object({
  file_ref: zod.string(),
  file_url: zod.string(),
  path: zod.string(),
  size: zod.number(),
  cache_status: zod
    .enum(['cached', 'caching', 'not_cached', 'not_cacheable'])
    .optional()
    .describe('Cache status for files in external storage backends.'),
});

/**
 * Delete a specific file from a fileset.

Permanently deletes the file from the storage backend.
Returns metadata about the deleted file.
 * @summary Delete a specific file from a fileset
 */
export const FilesDeleteFileParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
  path: zod.string(),
});

export const FilesDeleteFileResponse = zod.object({
  file_ref: zod.string(),
  file_url: zod.string(),
  path: zod.string(),
  size: zod.number(),
  cache_status: zod
    .enum(['cached', 'caching', 'not_cached', 'not_cacheable'])
    .optional()
    .describe('Cache status for files in external storage backends.'),
});

/**
 * List Files in Fileset.

Returns a list of files stored in the specified fileset.
Optionally filter by path prefix to list files under a specific directory.

Each file includes a cache_status field:
- "not_cacheable": File is on default storage, caching not applicable
- "cached": File exists in cache storage
- "caching": File is currently being downloaded and cached
- "not_cached": File not in cache, will be cached on next download
- null: External storage, but cache status not checked (use include_cache_status=true)
 * @summary List Fileset Files
 */
export const FilesListFilesetFilesParams = zod.object({
  workspace: zod.string(),
  name: zod.string(),
});

export const filesListFilesetFilesQueryIncludeCacheStatusDefault = false;

export const FilesListFilesetFilesQueryParams = zod.object({
  path: zod.string().optional().describe('Filter files by path prefix'),
  include_cache_status: zod
    .boolean()
    .default(filesListFilesetFilesQueryIncludeCacheStatusDefault)
    .describe(
      'Check and return cache status for each file. When false, storage files return null for cache_status.'
    ),
});

export const FilesListFilesetFilesResponse = zod.object({
  data: zod.array(
    zod.object({
      file_ref: zod.string(),
      file_url: zod.string(),
      path: zod.string(),
      size: zod.number(),
      cache_status: zod
        .enum(['cached', 'caching', 'not_cached', 'not_cacheable'])
        .optional()
        .describe('Cache status for files in external storage backends.'),
    })
  ),
});
